async function subirFotoTorneo(tid,tipo,input){
  const file=input.files[0];if(!file)return;
  if(file.size>3*1024*1024){toast('La imagen no puede superar 3MB');return;}
  toast('Subiendo imagen...');
  const reader=new FileReader();
  reader.onload=async e=>{const t=userData.torneos?.find(x=>x.id===tid);if(!t)return;if(tipo==='grupal')t.fotoGrupal=e.target.result;else t.fotoGanadores=e.target.result;await saveData();renderTorneo();toast('Foto guardada');};
  reader.readAsDataURL(file);
}
