let _torneosPublicosCache=[];
async function renderTorneosPublicos(){
  const el=document.getElementById('torneos-publicos-content');if(!el)return;
  el.innerHTML='<div class="empty">Cargando torneos p\u00fablicos...</div>';
  try{
    const snap=await db.collection('users').get();_torneosPublicosCache=[];
    snap.forEach(doc=>{const data=doc.data();(data.torneos||[]).filter(t=>t.publico).forEach(t=>{_torneosPublicosCache.push({...t,_ownerName:data.perfil?.apodo||'Usuario'});});});
    if(!_torneosPublicosCache.length){el.innerHTML='<div class="empty">No hay torneos p\u00fablicos por ahora</div>';return;}
    _torneosPublicosCache.sort((a,b)=>(b.fecha||'').localeCompare(a.fecha||''));
    const fmtN={americano:'Americano',todos:'Todos vs todos',grupos:'Grupos + Elim.',eliminacion:'Eliminaci\u00f3n directa',roundrobin:'Round Robin'};
    el.innerHTML=_torneosPublicosCache.map((t,i)=>{
      const jugados=t.partidos?.filter(p=>p.jugado).length||0,total=t.partidos?.length||0,pct=total?Math.round(jugados/total*100):0;
      return `<div onclick="abrirTorneoPublico(${i})" style="background:var(--color-background-primary,#fff);border:0.5px solid var(--color-border-tertiary,#e5e4df);border-radius:12px;margin-bottom:10px;padding:12px 14px;cursor:pointer" onmouseover="this.style.borderColor='var(--g,#1D9E75)'" onmouseout="this.style.borderColor='var(--color-border-tertiary,#e5e4df)'">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px"><div style="font-size:14px;font-weight:600;color:var(--color-text-primary,#1a1a18);flex:1">${t.nombre}</div><span class="badge ba" style="font-size:10px">${fmtN[t.formato]||t.formato}</span><span style="font-size:13px;color:var(--color-text-secondary,#888780)">\u203a</span></div>
        <div style="font-size:12px;color:var(--color-text-secondary,#888780);margin-bottom:8px">Por <strong>${t._ownerName}</strong>${t.fecha?' \u00b7 '+t.fecha:''}${t.club?' \u00b7 '+t.club:''}</div>
        ${total?`<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px"><div style="flex:1;height:4px;background:var(--color-border-tertiary,#e5e4df);border-radius:2px;overflow:hidden"><div style="height:100%;width:${pct}%;background:${pct===100?'var(--g,#1D9E75)':'var(--bl,#378ADD)'};border-radius:2px"></div></div><span style="font-size:11px;color:var(--color-text-secondary,#888780)">${jugados}/${total}</span></div>`:''}
        <div style="font-size:11px;color:var(--color-text-secondary,#888780)">${(t.jugadores||[]).slice(0,6).join(' \u00b7 ')}${(t.jugadores||[]).length>6?' \u00b7 ...':''}</div>
      </div>`;
    }).join('');
  }catch(e){el.innerHTML='<div class="empty">Error: '+e.message+'</div>';}
}
function abrirTorneoPublico(idx){
  const t=_torneosPublicosCache[idx];if(!t)return;
  document.getElementById('torneo-pub-titulo').textContent=t.nombre;
  const el=document.getElementById('torneo-pub-detalle-content');
  const meta=[];if(t._ownerName)meta.push('Por '+t._ownerName);if(t.fecha)meta.push(t.fecha);if(t.club)meta.push(t.club);if(t.hora)meta.push(t.hora+'hs');
  let html=`<div style="font-size:12px;color:var(--color-text-secondary,#888780);margin-bottom:14px;display:flex;flex-wrap:wrap;gap:6px">${meta.map(m=>`<span>${m}</span>`).join('<span style="opacity:.4">\u00b7</span>')}</div>`;
  html+=_renderTorneoDetalle(t,false);
  el.innerHTML=html;
  goTo('torneo-publico-detalle');
}
