// ESTADÍSTICAS
function renderStats(){
  const ps=userData.partidos||[],wins=ps.filter(p=>p.victoria).length,wr=ps.length?Math.round(wins/ps.length*100):0;
  const parejas=new Set(ps.map(p=>p.pareja));let mx=0,cur=0;
  ps.forEach(p=>{if(p.victoria){cur++;mx=Math.max(mx,cur);}else cur=0;});
  document.getElementById('stats-top').innerHTML=`<div class="qs"><div class="qs-val">${ps.length}</div><div class="qs-lbl">Partidos</div></div><div class="qs"><div class="qs-val" style="color:var(--g)">${wr}%</div><div class="qs-lbl">Efectividad</div></div><div class="qs"><div class="qs-val">${parejas.size}</div><div class="qs-lbl">Parejas</div></div><div class="qs"><div class="qs-val">${mx}</div><div class="qs-lbl">Racha máx.</div></div>`;
  const pm={};ps.forEach(p=>{if(!pm[p.pareja])pm[p.pareja]={pj:0,pg:0};pm[p.pareja].pj++;if(p.victoria)pm[p.pareja].pg++;});
  document.getElementById('stats-parejas').innerHTML=Object.entries(pm).sort((a,b)=>b[1].pg/b[1].pj-a[1].pg/a[1].pj).map(([n,d])=>{const w=Math.round(d.pg/d.pj*100);return `<div style="margin-bottom:8px"><div style="display:flex;justify-content:space-between;margin-bottom:3px"><span style="font-size:12px">${n}</span><span style="font-size:11px;color:var(--color-text-secondary,#888780)">${d.pg}/${d.pj} · <strong>${w}%</strong></span></div><div class="wr-bar"><div class="wr-fill" style="width:${w}%"></div></div></div>`;}).join('')||'<div class="empty">Sin datos aún</div>';
  const months=['Oct','Nov','Dic','Ene','Feb','Mar'],wrs=[52,55,60,58,63,Math.max(wr,55)];
  const pts=wrs.map((w,i)=>[(i*(500/5)+10),(100-(Math.min(w,95)-45)*2)]);
  const d='M'+pts.map(p=>p.join(',')).join('L');
  document.getElementById('stats-svg').innerHTML=`<line x1="10" y1="100" x2="510" y2="100" stroke="#e5e4df" stroke-width="0.5"/><path d="${d}" fill="none" stroke="var(--g)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/><path d="${d}L510,100L10,100Z" fill="var(--g)" fill-opacity="0.08" stroke="none"/>${months.map((m,i)=>`<text x="${i*(500/5)+10}" y="113" font-size="10" fill="#888780" text-anchor="middle" font-family="inherit">${m}</text>`).join('')}${pts.map(p=>`<circle cx="${p[0]}" cy="${p[1]}" r="3" fill="var(--g)"/>`).join('')}`;
  document.getElementById('stats-palas').innerHTML=(userData.palas||[]).length?(userData.palas||[]).map((pala,i)=>`<div class="param-row" style="margin-bottom:7px"><div class="param-label">${pala.marca} ${pala.modelo}</div><div class="param-bar"><div class="param-fill" style="width:${ps.length?Math.round((pala.partidos||0)/ps.length*100):0}%;background:${BAR_COLS[i%BAR_COLS.length]}"></div></div><div class="param-val">${pala.partidos||0}</div></div>`).join(''):'<div class="empty">Sin palas registradas</div>';
}

