// ── Pala por torneo (individual por jugador) ──
// Se guarda en userData.palasTorneos = { torneoId: palaId }
function _renderPalaTorneo(tid){
  const palas=userData?.palas||[];
  const palasTorneos=userData?.palasTorneos||{};
  const palaId=palasTorneos[tid]||null;
  const pala=palas.find(x=>x.id===palaId);
  if(!palas.length)return '';
  if(pala){
    return `<div style="margin-bottom:10px"><div style="display:flex;align-items:center;gap:8px;padding:8px 12px;background:rgba(55,138,221,0.08);border:0.5px solid rgba(55,138,221,0.3);border-radius:10px"><span style="font-size:18px">🏓</span><div style="flex:1"><div style="font-size:12px;font-weight:600;color:var(--bl,#378ADD)">${pala.marca} ${pala.modelo}</div><div style="font-size:10px;color:var(--color-text-secondary,#888780)">Mi pala en este torneo</div></div><button onclick="asignarPalaTorneo('${tid}')" style="background:none;border:0.5px solid var(--color-border-tertiary);border-radius:6px;padding:2px 8px;font-size:11px;color:var(--color-text-secondary,#888780);cursor:pointer;font-family:inherit">Cambiar</button></div></div>`;
  }
  return `<div style="margin-bottom:10px"><button onclick="asignarPalaTorneo('${tid}')" style="display:flex;align-items:center;gap:8px;width:100%;padding:10px 14px;border:1px dashed var(--color-border-secondary,#d3d1c7);border-radius:10px;cursor:pointer;font-size:12px;color:var(--color-text-secondary,#888780);background:none;font-family:inherit">🏓 ¿Qué pala usaste en este torneo?</button></div>`;
}
async function asignarPalaTorneo(tid){
  const palas=userData.palas||[];
  if(!palas.length){toast('No tienes palas registradas');return;}
  const palasTorneos=userData.palasTorneos||{};
  const palaActualId=palasTorneos[tid]||null;
  const existing=document.getElementById('_modal-pala-torneo');
  if(existing)existing.remove();
  const modal=document.createElement('div');
  modal.id='_modal-pala-torneo';
  modal.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9999;display:flex;align-items:flex-end;justify-content:center;padding:0';
  modal.innerHTML=`<div style="background:var(--color-background-primary,#fff);border-radius:16px 16px 0 0;padding:20px 16px 32px;width:100%;max-width:480px;max-height:70vh;overflow-y:auto">
    <div style="font-size:14px;font-weight:600;color:var(--color-text-primary);margin-bottom:16px;display:flex;justify-content:space-between;align-items:center">
      <span>🏓 Mi pala en este torneo</span>
      <button onclick="document.getElementById('_modal-pala-torneo').remove()" style="background:none;border:none;font-size:20px;cursor:pointer;color:var(--color-text-secondary);line-height:1">×</button>
    </div>
    <div style="display:flex;flex-direction:column;gap:8px">
      ${palas.map(p=>`<div onclick="_setPalaTorneo('${tid}','${p.id}')" style="display:flex;align-items:center;gap:10px;padding:10px 12px;border:0.5px solid ${palaActualId===p.id?'var(--bl,#378ADD)':'var(--color-border-tertiary,#e5e4df)'};border-radius:10px;cursor:pointer;background:${palaActualId===p.id?'rgba(55,138,221,0.08)':'var(--color-background-secondary,#f1efe8)'}">
        <span style="font-size:20px">🏓</span>
        <div style="flex:1">
          <div style="font-size:13px;font-weight:600;color:var(--color-text-primary)">${p.marca} ${p.modelo}</div>
          <div style="font-size:11px;color:var(--color-text-secondary,#888780)">${p.forma||''} · ${p.year||''}</div>
        </div>
        ${palaActualId===p.id?'<span style="color:var(--bl,#378ADD);font-weight:700;font-size:16px">✓</span>':''}
      </div>`).join('')}
      ${palaActualId?`<div onclick="_setPalaTorneo('${tid}',null)" style="text-align:center;padding:10px;font-size:12px;color:var(--color-text-secondary);cursor:pointer;border:0.5px solid var(--color-border-tertiary);border-radius:10px">Quitar pala asignada</div>`:''}
    </div>
  </div>`;
  document.body.appendChild(modal);
  modal.addEventListener('click',e=>{if(e.target===modal)modal.remove();});
}
async function _setPalaTorneo(tid,palaId){
  if(!userData.palasTorneos)userData.palasTorneos={};
  if(palaId)userData.palasTorneos[tid]=palaId;
  else delete userData.palasTorneos[tid];
  await saveData();
  document.getElementById('_modal-pala-torneo')?.remove();
  renderTorneo();
  toast(palaId?'Pala registrada para este torneo':'Pala removida');
}

// ── Vincular jugador en formatos sin grupos (todos / americano / eliminacion) ──
async function vincularJugadorNonGrupo(tid, parejaIdx, playerIdx){
  const t=userData.torneos?.find(x=>x.id===tid);if(!t)return;
  const nombre=t.jugadores?.[parejaIdx];if(!nombre)return;
  if(!t.equipoUids)t.equipoUids={};
  const uids=t.equipoUids[nombre]||[null,null];
  if(uids[playerIdx]){
    // Ya vinculado — reutilizar el menú existente pasando gr=null
    _mostrarMenuVinculado(t,nombre,uids,playerIdx,null);
    return;
  }
  const snap=await db.collection('users').get();
  const users=[];
  snap.forEach(doc=>{const d=doc.data();if(d.perfil?.apodo)users.push({uid:doc.id,apodo:_fmtApodo(d.perfil.apodo)});});
  if(!users.length){toast('No hay usuarios registrados');return;}
  const players=nombre.includes(' - ')?nombre.split(' - '):nombre.includes(' / ')?nombre.split(' / '):[nombre];
  const playerName=(players[playerIdx]||players[0]).trim();
  _mostrarModalVincular(t,nombre,users,playerIdx,playerName);
}

// ── Editar nombre de pareja en formatos sin grupos ──
async function editarNombreParejaDirecta(tid, idx){
  const t=userData.torneos?.find(x=>x.id===tid);if(!t)return;
  const nombreViejo=t.jugadores?.[idx];if(nombreViejo===undefined)return;
  const nuevoNombre=prompt('Editar nombre de la pareja:',nombreViejo);
  if(nuevoNombre===null)return;
  const nombre=nuevoNombre.trim();
  if(!nombre){toast('El nombre no puede estar vacío');return;}
  t.jugadores[idx]=nombre;
  t.partidos.forEach(p=>{if(p.eq1===nombreViejo)p.eq1=nombre;if(p.eq2===nombreViejo)p.eq2=nombre;});
  (t.playoffs||[]).forEach(m=>{if(m.eq1===nombreViejo)m.eq1=nombre;if(m.eq2===nombreViejo)m.eq2=nombre;});
  if(t.pagos&&t.pagos[nombreViejo]!==undefined){t.pagos[nombre]=t.pagos[nombreViejo];delete t.pagos[nombreViejo];}
  if(t.equipoUids&&t.equipoUids[nombreViejo]!==undefined){t.equipoUids[nombre]=t.equipoUids[nombreViejo];delete t.equipoUids[nombreViejo];}
  renderTorneo();saveData().catch(e=>console.error(e));toast('Nombre actualizado');
}
